 77→/** Result of evaluating governance policies for a tool call. */
 78→export type GovernanceVerdict =
 79→  | { readonly allowed: true }
 80→  | { readonly allowed: false; readonly reason: string; readonly outcome: "denied" | "rate_limited" };
 81→
 82→/**
 83→ * Evaluate governance policies (pure function).
 84→ *
 85→ * Rules:
 86→ *   - "requires_human_approval" condition -> denied
 87→ *   - max_per_day exceeded -> denied
 88→ *   - Multiple policies: most restrictive wins (any denial = denied)
 89→ */
 90→export function evaluateGovernancePolicies(
 91→  policies: GovernsPolicyRow[],
 92→  todayExecutionCount: number,
 93→): GovernanceVerdict {
 94→  for (const policy of policies) {
 95→    // Check requires_human_approval condition
 96→    if (policy.conditions === "requires_human_approval") {
 97→      return {
 98→        allowed: false,
 99→        reason: `Tool call denied by policy "${policy.policyTitle}": requires human approval`,
100→        outcome: "denied",
101→      };
102→    }
103→
104→    // Check max_per_day limit
105→    if (policy.max_per_day !== undefined && todayExecutionCount >= policy.max_per_day) {
106→      return {
107→        allowed: false,
108→        reason: `Tool call denied by policy "${policy.policyTitle}": daily limit of ${policy.max_per_day} exceeded (${todayExecutionCount} calls today)`,
109→        outcome: "denied",
110→      };
111→    }
112→  }
113→
114→  return { allowed: true };
115→}
