117→/**
118→ * Evaluate can_use rate limit (pure function).
119→ */
120→export function evaluateRateLimit(
121→  maxCallsPerHour: number | undefined,
122→  hourlyExecutionCount: number,
123→): GovernanceVerdict {
124→  if (maxCallsPerHour !== undefined && hourlyExecutionCount >= maxCallsPerHour) {
125→    return {
126→      allowed: false,
127→      reason: `Rate limit exceeded: ${hourlyExecutionCount}/${maxCallsPerHour} calls per hour`,
128→      outcome: "rate_limited",
129→    };
130→  }
131→
132→  return { allowed: true };
133→}
