217→/**
218→ * Execute all brain-native tool calls and return tool_result messages.
219→ *
220→ * - Each classified brain-native call is dispatched to its handler.
221→ * - Unknown handlers produce an error result (graceful, not HTTP 500).
222→ * - All errors are caught and returned as is_error tool_results.
223→ */
224→export async function executeBrainNativeTools(
225→  classifiedCalls: ClassifiedToolCall[],
226→  deps: ToolExecutorDeps,
227→): Promise<ToolExecutionResult[]> {
228→  const brainNativeCalls = classifiedCalls.filter(
229→    (c): c is Extract<ClassifiedToolCall, { classification: "brain-native" }> =>
230→      c.classification === "brain-native",
231→  );
232→
233→  const results: ToolExecutionResult[] = [];
234→
235→  for (const call of brainNativeCalls) {
236→    const handler = brainToolHandlers.get(call.toolUse.name);
237→
238→    if (!handler) {
239→      results.push({
240→        toolUseId: call.toolUse.id,
241→        content: JSON.stringify({
242→          error: `No handler registered for brain-native tool: ${call.toolUse.name}`,
243→        }),
244→        isError: true,
245→      });
246→      continue;
247→    }
248→
249→    const startMs = performance.now();
250→    try {
251→      const result = await handler(call.toolUse.input, deps);
252→      const durationMs = performance.now() - startMs;
253→      results.push({
254→        ...result,
255→        toolUseId: call.toolUse.id,
256→      });
257→
258→      // Fire-and-forget trace capture (do not block tool result delivery)
259→      captureToolTrace(
260→        {
261→          toolName: call.toolUse.name,
262→          workspaceId: deps.workspaceId,
263→          identityId: deps.identityId,
264→          sessionId: deps.sessionId,
265→          outcome: "success",
266→          durationMs,
267→          input: call.toolUse.input as Record<string, unknown>,
268→          output: { content: result.content },
269→        },
270→        { surreal: deps.surreal },
271→      ).catch((traceError) => {
272→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
273→          tool_name: call.toolUse.name,
274→          error: String(traceError),
275→        });
276→      });
277→    } catch (error) {
278→      const durationMs = performance.now() - startMs;
279→      log.warn("proxy.tool_executor.handler_error", "Brain-native tool execution failed", {
280→        tool_name: call.toolUse.name,
281→        tool_use_id: call.toolUse.id,
282→        error: String(error),
283→      });
284→      results.push({
285→        toolUseId: call.toolUse.id,
286→        content: JSON.stringify({
287→          error: `Tool execution failed: ${String(error)}`,
288→        }),
289→        isError: true,
290→      });
291→
292→      // Trace error outcome too
293→      captureToolTrace(
294→        {
295→          toolName: call.toolUse.name,
296→          workspaceId: deps.workspaceId,
297→          identityId: deps.identityId,
298→          sessionId: deps.sessionId,
299→          outcome: "error",
300→          durationMs,
301→        },
302→        { surreal: deps.surreal },
303→      ).catch((traceError) => {
304→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
305→          tool_name: call.toolUse.name,
306→          error: String(traceError),
307→        });
308→      });
309→    }
310→  }
311→
312→  return results;
313→}
