337→// ---------------------------------------------------------------------------
338→// Response Sanitization (Pure Functions)
339→// ---------------------------------------------------------------------------
340→
341→/** Headers that must be stripped from integration HTTP responses. */
342→const SENSITIVE_HEADERS: ReadonlySet<string> = new Set([
343→  "authorization",
344→  "set-cookie",
345→  "x-api-key",
346→  "www-authenticate",
347→]);
348→
349→/** JSON field names (lowercase) that must be recursively stripped from response bodies. */
350→const SENSITIVE_FIELDS: ReadonlySet<string> = new Set([
351→  "access_token",
352→  "refresh_token",
353→  "api_key",
354→  "password",
355→  "client_secret",
356→  "bearer_token",
357→]);
358→
359→/** Maximum response body size in bytes before truncation. */
360→const MAX_RESPONSE_BYTES = 100 * 1024; // 100KB
361→
362→/**
363→ * Strip sensitive headers from an HTTP response headers map.
364→ * Pure function: returns a new record with sensitive headers removed.
365→ */
366→export function sanitizeResponseHeaders(
367→  headers: Record<string, string>,
368→): Record<string, string> {
369→  const sanitized: Record<string, string> = {};
370→  for (const [key, value] of Object.entries(headers)) {
371→    if (!SENSITIVE_HEADERS.has(key.toLowerCase())) {
372→      sanitized[key] = value;
373→    }
374→  }
375→  return sanitized;
376→}
377→
378→/**
379→ * Recursively strip sensitive fields from a JSON value.
380→ * Pure function: returns a new value with credential fields removed.
381→ */
382→export function sanitizeResponseBody(value: unknown): unknown {
383→  if (value === null || value === undefined) return value;
384→
385→  if (Array.isArray(value)) {
386→    return value.map(sanitizeResponseBody);
387→  }
388→
389→  if (typeof value === "object") {
390→    const sanitized: Record<string, unknown> = {};
391→    for (const [key, fieldValue] of Object.entries(value as Record<string, unknown>)) {
392→      if (!SENSITIVE_FIELDS.has(key.toLowerCase())) {
393→        sanitized[key] = sanitizeResponseBody(fieldValue);
394→      }
395→    }
396→    return sanitized;
397→  }
398→
399→  return value;
400→}
401→
402→/**
403→ * Truncate a string to the maximum allowed byte size.
404→ * Pure function: appends a truncation marker if the content exceeds the limit.
405→ */
406→export function truncateResponse(content: string): string {
407→  const encoder = new TextEncoder();
408→  const bytes = encoder.encode(content);
409→  if (bytes.length <= MAX_RESPONSE_BYTES) return content;
410→
411→  const truncated = new TextDecoder().decode(bytes.slice(0, MAX_RESPONSE_BYTES));
412→  return `${truncated}\n\n[Response truncated: ${bytes.length} bytes exceeds ${MAX_RESPONSE_BYTES} byte limit]`;
413→}
414→
415→/**
416→ * Full sanitization pipeline for integration tool responses.
417→ * Pure function: sanitize body -> truncate -> return content string.
418→ */
419→export function sanitizeIntegrationResponse(
420→  responseBody: string,
421→  responseHeaders: Record<string, string>,
422→): { content: string; sanitizedHeaders: Record<string, string> } {
423→  const sanitizedHeaders = sanitizeResponseHeaders(responseHeaders);
424→
425→  // Try to parse and sanitize JSON body
426→  let sanitizedContent: string;
427→  try {
428→    const parsed = JSON.parse(responseBody);
429→    const sanitized = sanitizeResponseBody(parsed);
430→    sanitizedContent = JSON.stringify(sanitized);
431→  } catch {
432→    // Not JSON -- use raw body
433→    sanitizedContent = responseBody;
434→  }
435→
436→  const truncatedContent = truncateResponse(sanitizedContent);
437→
438→  return { content: truncatedContent, sanitizedHeaders };
439→}
