441→// ---------------------------------------------------------------------------
442→// Effect Boundary: executeIntegrationTools
443→// ---------------------------------------------------------------------------
444→
445→/**
446→ * Execute all integration tool calls via HTTP with brokered credentials.
447→ *
448→ * For each integration tool call:
449→ *   1. Resolve credentials via credential-resolver
450→ *   2. Execute HTTP call to integration API
451→ *   3. Sanitize response (strip auth headers + credential fields)
452→ *   4. Truncate to 100KB
453→ *   5. Return as tool_result
454→ *   6. Write trace record
455→ *
456→ * Errors are returned as is_error tool_results, never thrown as exceptions.
457→ */
458→export async function executeIntegrationTools(
459→  classifiedCalls: ClassifiedToolCall[],
460→  deps: IntegrationExecutorDeps,
461→): Promise<ToolExecutionResult[]> {
462→  const integrationCalls = classifiedCalls.filter(
463→    (c): c is Extract<ClassifiedToolCall, { classification: "integration" }> =>
464→      c.classification === "integration",
465→  );
466→
467→  const results: ToolExecutionResult[] = [];
468→
469→  for (const call of integrationCalls) {
470→    const startMs = performance.now();
471→    const providerRef = call.resolvedTool.toolkit;
472→
473→    try {
474→      // Step 0: Governance check (BEFORE credential resolution)
475→      const governancePolicies = await fetchGovernancePolicies(
476→        deps.surreal,
477→        call.toolUse.name,
478→      );
479→
480→      if (governancePolicies.length > 0) {
481→        const todayCount = await countTodayToolExecutions(
482→          deps.surreal,
483→          call.toolUse.name,
484→          deps.workspaceId,
485→        );
486→
487→        const governanceVerdict = evaluateGovernancePolicies(governancePolicies, todayCount);
488→
489→        if (!governanceVerdict.allowed) {
490→          const durationMs = performance.now() - startMs;
491→          results.push({
492→            toolUseId: call.toolUse.id,
493→            content: JSON.stringify({ error: governanceVerdict.reason }),
494→            isError: true,
495→          });
496→
497→          captureToolTrace(
498→            {
499→              toolName: call.toolUse.name,
500→              workspaceId: deps.workspaceId,
501→              identityId: deps.identityId,
502→              sessionId: deps.sessionId,
503→              outcome: governanceVerdict.outcome,
504→              durationMs,
505→              input: { tool_kind: "integration", governance_denial: governanceVerdict.reason },
506→            },
507→            { surreal: deps.surreal },
508→          ).catch((traceError) => {
509→            log.warn("proxy.governance.trace_failed", "Governance trace capture failed", {
510→              tool_name: call.toolUse.name,
511→              error: String(traceError),
512→            });
513→          });
514→          continue;
515→        }
516→      }
517→
518→      // Step 0.5: Rate limit check on can_use edge
519→      if (deps.identityId) {
520→        const { maxCallsPerHour } = await fetchCanUseRateLimit(
521→          deps.surreal,
522→          deps.identityId,
523→          call.toolUse.name,
524→        );
525→
526→        if (maxCallsPerHour !== undefined) {
527→          const hourlyCount = await countHourlyToolExecutions(
528→            deps.surreal,
529→            call.toolUse.name,
530→            deps.workspaceId,
531→            deps.identityId,
532→          );
533→
534→          const rateLimitVerdict = evaluateRateLimit(maxCallsPerHour, hourlyCount);
535→
536→          if (!rateLimitVerdict.allowed) {
537→            const durationMs = performance.now() - startMs;
538→            results.push({
539→              toolUseId: call.toolUse.id,
540→              content: JSON.stringify({ error: rateLimitVerdict.reason }),
541→              isError: true,
542→            });
543→
544→            captureToolTrace(
545→              {
546→                toolName: call.toolUse.name,
547→                workspaceId: deps.workspaceId,
548→                identityId: deps.identityId,
549→                sessionId: deps.sessionId,
550→                outcome: rateLimitVerdict.outcome,
551→                durationMs,
552→                input: { tool_kind: "integration", rate_limit_denial: rateLimitVerdict.reason },
553→              },
554→              { surreal: deps.surreal },
555→            ).catch((traceError) => {
556→              log.warn("proxy.rate_limit.trace_failed", "Rate limit trace capture failed", {
557→                tool_name: call.toolUse.name,
558→                error: String(traceError),
559→              });
560→            });
561→            continue;
562→          }
563→        }
564→      }
565→
566→      // Step 1: Resolve credentials
567→      if (!deps.identityId) {
568→        results.push({
569→          toolUseId: call.toolUse.id,
570→          content: JSON.stringify({ error: "Identity required for integration tool calls" }),
571→          isError: true,
572→        });
573→        continue;
574→      }
575→
576→      const credentialResolverDeps: CredentialResolverDeps = {
577→        surreal: deps.surreal,
578→        toolEncryptionKey: deps.toolEncryptionKey,
579→      };
580→
581→      const credResult = await resolveCredentialsForTool(
582→        call.toolUse.name,
583→        deps.identityId,
584→        credentialResolverDeps,
585→      );
586→
587→      if (!credResult.ok) {
588→        const durationMs = performance.now() - startMs;
589→        results.push({
590→          toolUseId: call.toolUse.id,
591→          content: JSON.stringify({ error: `Credential resolution failed: ${credResult.error}` }),
592→          isError: true,
593→        });
594→
595→        captureToolTrace(
596→          {
597→            toolName: call.toolUse.name,
598→            workspaceId: deps.workspaceId,
599→            identityId: deps.identityId,
600→            sessionId: deps.sessionId,
601→            outcome: "error",
602→            durationMs,
603→            input: { tool_kind: "integration", credential_provider: providerRef },
604→          },
605→          { surreal: deps.surreal },
606→        ).catch((traceError) => {
607→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
608→            tool_name: call.toolUse.name,
609→            error: String(traceError),
610→          });
611→        });
612→        continue;
613→      }
614→
615→      // Step 2: Build and execute HTTP request
616→      // The tool input should contain the endpoint URL or we derive it from provider config
617→      const endpointUrl = typeof call.toolUse.input.endpoint_url === "string"
618→        ? call.toolUse.input.endpoint_url
619→        : typeof call.toolUse.input.url === "string"
620→          ? call.toolUse.input.url
621→          : undefined;
622→
623→      if (!endpointUrl) {
624→        const durationMs = performance.now() - startMs;
625→        results.push({
626→          toolUseId: call.toolUse.id,
627→          content: JSON.stringify({ error: "Integration tool call missing endpoint_url or url in input" }),
628→          isError: true,
629→        });
630→
631→        captureToolTrace(
632→          {
633→            toolName: call.toolUse.name,
634→            workspaceId: deps.workspaceId,
635→            identityId: deps.identityId,
636→            sessionId: deps.sessionId,
637→            outcome: "error",
638→            durationMs,
639→            input: { tool_kind: "integration", credential_provider: providerRef },
640→          },
641→          { surreal: deps.surreal },
642→        ).catch((traceError) => {
643→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
644→            tool_name: call.toolUse.name,
645→            error: String(traceError),
646→          });
647→        });
648→        continue;
649→      }
650→
651→      const httpMethod = typeof call.toolUse.input.method === "string"
652→        ? call.toolUse.input.method.toUpperCase()
653→        : "POST";
654→
655→      const requestHeaders: Record<string, string> = {
656→        "Content-Type": "application/json",
657→        ...credResult.headers,
658→      };
659→
660→      // Build request body from tool input (excluding meta fields)
661→      const { endpoint_url: _eu, url: _u, method: _m, ...bodyInput } = call.toolUse.input;
662→      const hasBody = httpMethod !== "GET" && httpMethod !== "HEAD" && Object.keys(bodyInput).length > 0;
663→
664→      const fetchOptions: RequestInit = {
665→        method: httpMethod,
666→        headers: requestHeaders,
667→        ...(hasBody ? { body: JSON.stringify(bodyInput) } : {}),
668→      };
669→
670→      const httpResponse = await fetch(endpointUrl, fetchOptions);
671→      const responseBody = await httpResponse.text();
672→      const durationMs = performance.now() - startMs;
673→
674→      // Step 3-4: Sanitize and truncate
675→      const responseHeaders: Record<string, string> = {};
676→      httpResponse.headers.forEach((value, key) => {
677→        responseHeaders[key] = value;
678→      });
679→
680→      const { content } = sanitizeIntegrationResponse(responseBody, responseHeaders);
681→
682→      // Step 5: Return as tool_result
683→      const isError = httpResponse.status >= 400;
684→      const resultContent = isError
685→        ? JSON.stringify({
686→            error: `Integration API returned ${httpResponse.status}`,
687→            status: httpResponse.status,
688→            body: content,
689→          })
690→        : content;
691→
692→      results.push({
693→        toolUseId: call.toolUse.id,
694→        content: resultContent,
695→        isError,
696→      });
697→
698→      // Step 6: Write trace record
699→      captureToolTrace(
700→        {
701→          toolName: call.toolUse.name,
702→          workspaceId: deps.workspaceId,
703→          identityId: deps.identityId,
704→          sessionId: deps.sessionId,
705→          outcome: isError ? "error" : "success",
706→          durationMs,
707→          input: { tool_kind: "integration", credential_provider: providerRef },
708→          output: { status: httpResponse.status, content_length: content.length },
709→        },
710→        { surreal: deps.surreal },
711→      ).catch((traceError) => {
712→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
713→          tool_name: call.toolUse.name,
714→          error: String(traceError),
715→        });
716→      });
717→    } catch (error) {
718→      const durationMs = performance.now() - startMs;
719→
720→      // Integration errors are tool_result errors, not HTTP 500s
721→      log.warn("proxy.integration_executor.error", "Integration tool execution failed", {
722→        tool_name: call.toolUse.name,
723→        tool_use_id: call.toolUse.id,
724→        error: String(error),
725→      });
726→
727→      results.push({
728→        toolUseId: call.toolUse.id,
729→        content: JSON.stringify({
730→          error: `Integration tool execution failed: ${String(error)}`,
731→        }),
732→        isError: true,
733→      });
734→
735→      captureToolTrace(
736→        {
737→          toolName: call.toolUse.name,
738→          workspaceId: deps.workspaceId,
739→          identityId: deps.identityId,
740→          sessionId: deps.sessionId,
741→          outcome: "error",
742→          durationMs,
743→          input: { tool_kind: "integration", credential_provider: providerRef },
744→        },
745→        { surreal: deps.surreal },
746→      ).catch((traceError) => {
747→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
748→          tool_name: call.toolUse.name,
749→          error: String(traceError),
750→        });
751→      });
752→    }
753→  }
754→
755→  return results;
756→}
