302→/**
303→ * Seed an mcp_tool record directly in SurrealDB for test preconditions.
304→ */
305→export async function seedTool(
306→  surreal: Surreal,
307→  workspaceId: string,
308→  options: {
309→    name: string;
310→    toolkit: string;
311→    description?: string;
312→    riskLevel?: "low" | "medium" | "high" | "critical";
313→    status?: "active" | "disabled";
314→    providerId?: string;
315→    inputSchema?: Record<string, unknown>;
316→  },
317→): Promise<{ toolId: string }> {
318→  const toolId = `tool-${crypto.randomUUID()}`;
319→  const toolRecord = new RecordId("mcp_tool", toolId);
320→  const workspaceRecord = new RecordId("workspace", workspaceId);
321→
322→  const content: Record<string, unknown> = {
323→    name: options.name,
324→    toolkit: options.toolkit,
325→    description: options.description ?? `${options.name} tool`,
326→    input_schema: options.inputSchema ?? { type: "object", properties: {} },
327→    risk_level: options.riskLevel ?? "medium",
328→    workspace: workspaceRecord,
329→    status: options.status ?? "active",
330→    created_at: new Date(),
331→  };
332→
333→  if (options.providerId) {
334→    content.provider = new RecordId("credential_provider", options.providerId);
335→  }
336→
337→  await surreal.query(`CREATE $tool CONTENT $content;`, {
338→    tool: toolRecord,
339→    content,
340→  });
341→
342→  return { toolId };
343→}
