436→/**
437→ * Seed a can_use edge (grant) directly in SurrealDB for test preconditions.
438→ */
439→export async function seedGrant(
440→  surreal: Surreal,
441→  identityId: string,
442→  toolId: string,
443→  options?: { maxCallsPerHour?: number },
444→): Promise<void> {
445→  const identityRecord = new RecordId("identity", identityId);
446→  const toolRecord = new RecordId("mcp_tool", toolId);
447→
448→  const setClause = options?.maxCallsPerHour
449→    ? `SET granted_at = time::now(), max_calls_per_hour = ${options.maxCallsPerHour}`
450→    : `SET granted_at = time::now()`;
451→
452→  await surreal.query(
453→    `RELATE $identity->can_use->$tool ${setClause};`,
454→    { identity: identityRecord, tool: toolRecord },
455→  );
456→}
