464→  options: {
465→    title: string;
466→    status?: "active" | "draft" | "deprecated";
467→    identityId?: string;
468→  },
469→): Promise<{ policyId: string }> {
470→  const policyId = `policy-${crypto.randomUUID()}`;
471→  const policyRecord = new RecordId("policy", policyId);
472→  const workspaceRecord = new RecordId("workspace", workspaceId);
473→  const createdByRecord = new RecordId(
474→    "identity",
475→    options.identityId ?? `id-${crypto.randomUUID()}`,
476→  );
477→
478→  // Ensure identity exists for created_by reference
479→  if (!options.identityId) {
480→    await surreal.query(`CREATE $identity CONTENT $content;`, {
481→      identity: createdByRecord,
482→      content: {
483→        name: "Policy Author",
484→        type: "human",
485→        identity_status: "active",
486→        workspace: workspaceRecord,
487→        created_at: new Date(),
488→      },
489→    });
490→  }
491→
492→  await surreal.query(`CREATE $policy CONTENT $content;`, {
493→    policy: policyRecord,
494→    content: {
495→      title: options.title,
496→      description: `Governance policy: ${options.title}`,
497→      status: options.status ?? "active",
498→      version: 1,
499→      workspace: workspaceRecord,
500→      created_by: createdByRecord,
501→      selector: {},
502→      rules: [],
503→      created_at: new Date(),
504→    },
505→  });
506→
507→  return { policyId };
508→}
