510→/**
511→ * Seed a governs_tool edge directly in SurrealDB for test preconditions.
512→ */
513→export async function seedGovernance(
514→  surreal: Surreal,
515→  policyId: string,
516→  toolId: string,
517→  options?: { conditions?: string; maxPerCall?: number; maxPerDay?: number },
518→): Promise<void> {
519→  const policyRecord = new RecordId("policy", policyId);
520→  const toolRecord = new RecordId("mcp_tool", toolId);
521→
522→  const setClauses: string[] = [];
523→  if (options?.conditions) setClauses.push(`conditions = $conditions`);
524→  if (options?.maxPerCall !== undefined) setClauses.push(`max_per_call = ${options.maxPerCall}`);
525→  if (options?.maxPerDay !== undefined) setClauses.push(`max_per_day = ${options.maxPerDay}`);
526→
527→  const setString = setClauses.length > 0 ? `SET ${setClauses.join(", ")}` : "";
528→
529→  await surreal.query(
530→    `RELATE $policy->governs_tool->$tool ${setString};`,
531→    { policy: policyRecord, tool: toolRecord, conditions: options?.conditions },
532→  );
533→}
